function cleanString(str) {
  if (typeof str !== 'string') return str;

  // 1. إزالة null characters + أحرف تحكم
  str = str.replace(/[\u0000-\u001F\u007F-\u009F]/g, '');

  // 2. إزالة escape sequences غير مكتملة مثل \u12
  str = str.replace(/\\u[0-9a-fA-F]{0,3}(?![0-9a-fA-F])/g, '');

  // 3. محاولة إصلاح UTF-8 encoding
  try {
    str = decodeURIComponent(encodeURIComponent(str));
  } catch (e) {
    console.warn('Encoding error:', e.message);
  }

  return str;
}

if (item.json.content) {
  item.json.content = cleanString(item.json.content);
}

if (item.json.metadata) {
  let meta = item.json.metadata;

  if (typeof meta === 'string') {
    meta = cleanString(meta);
    try {
      meta = JSON.parse(meta);
    } catch (e) {
      console.warn('Invalid metadata JSON:', e.message);
      meta = {};
    }
  }

  if (typeof meta === 'object' && meta !== null) {
    for (const key in meta) {
      if (typeof meta[key] === 'string') {
        meta[key] = cleanString(meta[key]);
      }
    }
  }

  item.json.metadata = meta;
}

return item;

