// الكود ده هيعمل "escaping" لعلامات التنصيص المزدوجة
// وهيشيل أي أحرف تحكم غير صالحة في JSON.
// وهييشيل كمان علامات النجوم (*).
for (const item of items) {
  if (item.json && item.json.output) {
    let cleanedOutput = item.json.output;

    // اهرب علامات التنصيص المزدوجة اللي مش مهربة بالفعل
    cleanedOutput = cleanedOutput.replace(/(?<!\\)"/g, '\\"');

    // شيل الأحرف التحكمية (control characters) غير الصالحة في JSON
    cleanedOutput = cleanedOutput.replace(/[\u0000-\u001F\u007F-\u009F]/g, '');

    // شيل علامات النجوم (*)
    cleanedOutput = cleanedOutput.replace(/\*/g, ''); //

    item.json.output = cleanedOutput;
  }
}
return items;

