const inputItems = $input.all();
const results = [];
const aggregatedComponents = {};

for (const item of inputItems) {
    const output = item.json.output;
    let parsedJson;

    // Use a regex to extract the raw JSON string from the markdown block
    const jsonMatch = output.match(/```json\n([\s\S]*?)\n```/);

    if (jsonMatch && jsonMatch[1]) {
        try {
            parsedJson = JSON.parse(jsonMatch[1]);
        } catch (e) {
            console.error('Error parsing JSON from AI Agent output:', e);
            continue; // Skip this item and move to the next one
        }
    } else {
        // If no markdown block is found, assume the output is raw JSON
        try {
            parsedJson = JSON.parse(output);
        } catch (e) {
            console.error('Error parsing raw JSON from AI Agent output:', e);
            continue; // Skip this item
        }
    }

    if (parsedJson) {
        for (const comp of parsedJson) {
            const name = comp.componentName;
            const quantity = parseFloat(comp.quantity);

            if (name && !isNaN(quantity)) {
                if (aggregatedComponents[name]) {
                    aggregatedComponents[name] += quantity;
                } else {
                    aggregatedComponents[name] = quantity;
                }
            }
        }
    }
}

for (const name in aggregatedComponents) {
    results.push({
        json: {
            "componentName": name,
            "quantity": aggregatedComponents[name]
        }
    });
}

return results;

